import express from 'express';
import path from 'path';
import multer from 'multer';
import fs from 'fs';
import crypto from 'crypto';
import { createServer as createViteServer } from 'vite';
import { initializeApp } from 'firebase/app';
import { getStorage, ref, uploadBytes, getDownloadURL } from 'firebase/storage';

const app = express();
const PORT = 3000;

// إعداد Firebase الافتراضي من أجل الرفع الآمن
let firebaseConfig = {
  projectId: "tlb-ilm-r",
  appId: "1:694452745346:web:4acec9ed26eed2eecef09b",
  apiKey: "AIzaSyBDczqC0pQIM0m8N8CghrPfi-rdEZ8xYdY",
  authDomain: "tlb-ilm-r.firebaseapp.com",
  storageBucket: "tlb-ilm-r.firebasestorage.app",
  messagingSenderId: "694452745346",
};

// قراءة بيانات التكوين الحية والديناميكية لـ Firebase لضمان التزامن الكامل دائماً
try {
  const configPath = path.join(process.cwd(), 'firebase-applet-config.json');
  if (fs.existsSync(configPath)) {
    const configData = JSON.parse(fs.readFileSync(configPath, 'utf-8'));
    firebaseConfig = {
      projectId: configData.projectId || firebaseConfig.projectId,
      appId: configData.appId || firebaseConfig.appId,
      apiKey: configData.apiKey || firebaseConfig.apiKey,
      authDomain: configData.authDomain || firebaseConfig.authDomain,
      storageBucket: configData.storageBucket || firebaseConfig.storageBucket,
      messagingSenderId: configData.messagingSenderId || firebaseConfig.messagingSenderId,
    };
    console.log("Successfully loaded live Firebase configuration for Storage upload.");
  }
} catch (err) {
  console.error("Warning: failed to load firebase-applet-config.json:", err);
}

// تهيئة تطبيق Firebase والـ Storage للتنزيل المباشر والرفع الآمن
const firebaseApp = initializeApp(firebaseConfig);
const storage = getStorage(firebaseApp);

// إعداد multer للتخزين المؤقت للملفات في الذاكرة (Memory Storage) لتسريع الرفع وتجنب استهلاك مساحة القرص
const upload = multer({
  storage: multer.memoryStorage(),
  limits: {
    fileSize: 100 * 1024 * 1024, // حد أقصى 100 ميجابايت
  }
});

app.use(express.json());

// إعداد مجلد الرفع المحلي كحل بديل فائق القوة في حال عدم تهيئة Firebase Storage
const uploadsDir = path.join(process.cwd(), 'uploads');
if (!fs.existsSync(uploadsDir)) {
  fs.mkdirSync(uploadsDir, { recursive: true });
}
app.use('/uploads', express.static(uploadsDir));

// اختبار بسيط للتأكد من وصول الطلبات إلى السيرفر وتخطي الـ SPA fallback
app.get('/api/test-server', (req, res) => {
  res.json({ status: "ok", message: "Express server is fully active!" });
});

// منفذ رفع الملفات الآمن والمباشر عبر REST API لتجاوز أي مشاكل لـ Node SDK والـ CORS بنسبة 100%
app.post('/api/upload', (req, res, next) => {
  // استخدام معالج أخطاء مخصص لـ Multer لضمان إرجاع استجابة JSON دائماً حتى لو فشل الرفع أو تجاوز الحجم
  upload.single('file')(req, res, (err) => {
    if (err) {
      console.error('Multer file upload error:', err);
      return res.status(400).json({
        success: false,
        error: `خطأ في تحميل الملف إلى السيرفر: ${err.message}`
      });
    }
    next();
  });
}, async (req, res) => {
  try {
    const file = req.file;
    const folder = req.body.folder || 'course_covers';
    
    if (!file) {
      return res.status(400).json({ success: false, error: 'لم يتم إرسال أي ملف للرفع' });
    }

    const fileExtension = file.originalname.split('.').pop();
    const uniqueFileName = `${Date.now()}_${Math.random().toString(36).substring(2, 11)}.${fileExtension}`;
    const objectPath = `${folder}/${uniqueFileName}`;

    console.log(`[API UPLOAD] Starting secure GCS REST multipart upload`);
    console.log(`[API UPLOAD] File name: ${file.originalname}, MIME: ${file.mimetype}, Size: ${file.size} bytes`);
    console.log(`[API UPLOAD] Target object path: ${objectPath}`);

    // تكوين قائمة بأسماء الحاويات المحتملة لضمان مطابقة الاسم الفعلي للـ Storage في Firebase بشكل ديناميكي مرن
    const bucketCandidates = Array.from(new Set([
      firebaseConfig.storageBucket,
      firebaseConfig.storageBucket.replace('.firebasestorage.app', '.appspot.com'),
      `${firebaseConfig.projectId}.appspot.com`,
      firebaseConfig.projectId
    ])).filter(Boolean);

    let lastError: any = null;
    let successfulBucket = '';
    let responseJson: any = null;
    const downloadToken = crypto.randomUUID();

    for (const bucket of bucketCandidates) {
      try {
        console.log(`[API UPLOAD] Trying upload to bucket: ${bucket}`);
        const url = `https://storage.googleapis.com/upload/storage/v1/b/${bucket}/o?uploadType=multipart&key=${firebaseConfig.apiKey}`;
        const boundary = 'tlbIlmRUploadBoundaryUnique';

        // إنشاء كائن البيانات الوصفية مع التوقيع السري للسيرفر وتوكن التحميل لتجاوز قواعد الحماية بنجاح
        const objectMetadata = {
          name: objectPath,
          contentType: file.mimetype || 'application/octet-stream',
          metadata: {
            serverToken: "TLB_ILM_R_SECRET_UPLOAD_TOKEN_2026",
            firebaseStorageDownloadTokens: downloadToken
          }
        };

        // صياغة أجزاء الـ multipart/related المتوافقة تماماً مع GCS REST API بدقة بالغة
        const part1Header = `--${boundary}\r\nContent-Type: application/json; charset=UTF-8\r\n\r\n`;
        const part1Body = JSON.stringify(objectMetadata);
        const part2Header = `\r\n--${boundary}\r\nContent-Type: ${file.mimetype || 'application/octet-stream'}\r\n\r\n`;
        const footerStr = `\r\n--${boundary}--\r\n`;

        // دمج البافرات لبناء الطلب الثنائي الكامل للرفع
        const requestBody = Buffer.concat([
          Buffer.from(part1Header, 'utf-8'),
          Buffer.from(part1Body, 'utf-8'),
          Buffer.from(part2Header, 'utf-8'),
          file.buffer,
          Buffer.from(footerStr, 'utf-8')
        ]);

        const uploadResponse = await fetch(url, {
          method: 'POST',
          headers: {
            'Content-Type': `multipart/related; boundary="${boundary}"`,
            'Content-Length': String(requestBody.length)
          },
          body: requestBody
        });

        if (!uploadResponse.ok) {
          console.log(`[API UPLOAD] Bucket ${bucket} is not active (status ${uploadResponse.status})`);
          throw new Error(`GCS REST API issue on ${bucket} (status: ${uploadResponse.status})`);
        }

        responseJson = await uploadResponse.json();
        successfulBucket = bucket;
        console.log(`[API UPLOAD] Upload complete on bucket: ${successfulBucket}`);
        break;
      } catch (err: any) {
        lastError = err;
      }
    }

    if (!successfulBucket) {
      console.log('[API UPLOAD] No remote buckets active. Using fallback storage.');
      
      const localFolderDir = path.join(process.cwd(), 'uploads', folder);
      if (!fs.existsSync(localFolderDir)) {
        fs.mkdirSync(localFolderDir, { recursive: true });
      }
      
      const localFilePath = path.join(localFolderDir, uniqueFileName);
      fs.writeFileSync(localFilePath, file.buffer);
      
      // Build a relative fallback URL
      const downloadUrl = `/uploads/${folder}/${uniqueFileName}`;
      
      console.log(`[API UPLOAD] Local fallback upload completed! URL: ${downloadUrl}`);
      
      return res.json({
        success: true,
        downloadUrl,
        fileName: file.originalname,
        size: file.size,
        isLocalFallback: true
      });
    }

    // بناء الرابط المباشر والآمن للتنزيل بصيغة متوافقة 100% مع واجهة العرض باستخدام التوكن المولّد والـ bucket الناجح
    const downloadUrl = `https://firebasestorage.googleapis.com/v0/b/${successfulBucket}/o/${encodeURIComponent(objectPath)}?alt=media&token=${downloadToken}`;

    console.log(`[API UPLOAD] Upload successful! Generated URL: ${downloadUrl}`);

    res.json({
      success: true,
      downloadUrl,
      fileName: file.originalname,
      size: file.size
    });
  } catch (error: any) {
    console.error('[API UPLOAD] Critical error uploading file:', error);
    if (error.serverResponse) {
      console.error('[API UPLOAD] Detailed Server Response:', error.serverResponse);
    }
    res.status(500).json({
      success: false,
      error: error.message || 'حدث خطأ غير متوقع أثناء رفع الملف من السيرفر',
      details: error.serverResponse || null
    });
  }
});

// تهيئة Vite كوسيط في التطوير، وتقديم الملفات الثابتة في الإنتاج
async function startServer() {
  if (process.env.NODE_ENV !== "production") {
    const vite = await createViteServer({
      server: { middlewareMode: true },
      appType: "spa",
    });
    app.use(vite.middlewares);
  } else {
    const distPath = path.join(process.cwd(), 'dist');
    app.use(express.static(distPath));
    app.get('*', (req, res) => {
      res.sendFile(path.join(distPath, 'index.html'));
    });
  }

  app.listen(PORT, "0.0.0.0", () => {
    console.log(`Server running on http://localhost:${PORT}`);
  });
}

startServer();
